import{_ as a,X as e,Y as p,$ as r}from"./framework-7663974c.js";const i={},h=r('<h1 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a></h1><h2 id="tar" tabindex="-1"><a class="header-anchor" href="#tar" aria-hidden="true">#</a> .tar</h2><p>（注：tar是打包，不是压缩！）</p><p>解包：</p><p>tar xvf FileName.tar</p><p>打包：</p><p>tar cvf FileName.tar DirName</p><h2 id="gz" tabindex="-1"><a class="header-anchor" href="#gz" aria-hidden="true">#</a> .gz</h2><p>解压1：</p><p>gunzip FileName.gz</p><p>解压2：</p><p>gzip -d FileName.gz</p><p>压缩：</p><p>gzip FileName</p><h2 id="tar-gz-和-tgz" tabindex="-1"><a class="header-anchor" href="#tar-gz-和-tgz" aria-hidden="true">#</a> .tar.gz 和 .tgz</h2><p>解压：</p><p>tar zxvf FileName.tar.gz</p><p>压缩：</p><p>tar zcvf FileName.tar.gz DirName</p><h2 id="tar-与-find-结合使用" tabindex="-1"><a class="header-anchor" href="#tar-与-find-结合使用" aria-hidden="true">#</a> tar 与 find 结合使用</h2><p>将按照自己条件查询出来的文件名写入到一个文件 tmp.list 中</p><p>find /tmp -cmin +24 &gt; tmp.list</p><p>然后将文件中记录到的所有文件加入到压缩包中</p><p>tar -T tmp.list -czvf tmp.expire.tar.gz</p><h2 id="bz2" tabindex="-1"><a class="header-anchor" href="#bz2" aria-hidden="true">#</a> .bz2</h2><p>解压1：</p><p>bzip2 -d FileName.bz2</p><p>解压2：</p><p>bunzip2 FileName.bz2</p><p>压缩：</p><p>bzip2 -z FileName</p><h2 id="tar-bz2" tabindex="-1"><a class="header-anchor" href="#tar-bz2" aria-hidden="true">#</a> .tar.bz2</h2><p>解压：</p><p>tar jxvf FileName.tar.bz2</p><p>压缩：</p><p>tar jcvf FileName.tar.bz2 DirName</p><h2 id="bz" tabindex="-1"><a class="header-anchor" href="#bz" aria-hidden="true">#</a> .bz</h2><p>解压1：</p><p>bzip2 -d FileName.bz</p><p>解压2：</p><p>bunzip2 FileName.bz</p><p>压缩：未知</p><h2 id="tar-bz" tabindex="-1"><a class="header-anchor" href="#tar-bz" aria-hidden="true">#</a> .tar.bz</h2><p>解压：</p><p>tar jxvf FileName.tar.bz</p><p>压缩：未知</p><h2 id="z" tabindex="-1"><a class="header-anchor" href="#z" aria-hidden="true">#</a> .Z</h2><p>解压：</p><p>uncompress FileName.Z</p><p>压缩：</p><p>compress FileName</p><h2 id="tar-z" tabindex="-1"><a class="header-anchor" href="#tar-z" aria-hidden="true">#</a> .tar.Z</h2><p>解压：</p><p>tar Zxvf FileName.tar.Z</p><p>压缩：</p><p>tar Zcvf FileName.tar.Z DirName</p><h2 id="zip" tabindex="-1"><a class="header-anchor" href="#zip" aria-hidden="true">#</a> .zip</h2><p>解压：</p><p>unzip FileName.zip</p><p>压缩：</p><p>zip -r FileName.zip DirName</p><h2 id="rar" tabindex="-1"><a class="header-anchor" href="#rar" aria-hidden="true">#</a> .rar</h2><p>解压：</p><p>rar x FileName.rar</p><p>压缩：</p><p>rar a FileName.rar DirName</p><h2 id="lha" tabindex="-1"><a class="header-anchor" href="#lha" aria-hidden="true">#</a> .lha</h2><p>解压：</p><p>lha -e FileName.lha</p><p>压缩：</p><p>lha -a FileName.lha FileName</p><h2 id="rpm" tabindex="-1"><a class="header-anchor" href="#rpm" aria-hidden="true">#</a> .rpm</h2><p>解包：</p><p>rpm2cpio FileName.rpm | cpio -div</p><p>安装：</p><p>rpm -ivh awstats-7.0-1.noarch.rpm</p>',76),t=[h];function d(n,l){return e(),p("div",null,t)}const z=a(i,[["render",d],["__file","解压缩.html.vue"]]);export{z as default};
